  # Group objects by (subject, predicate) to allow natural aggregation
      grouped = {}
      for triple in triples:
          key = (triple.subject, triple.predicate)
          grouped.setdefault(key, []).append(triple.object)

      # Helper to join multiple objects nicely
      def join_objects(objs: list[str]) -> str:
          if not objs:
              return ""
          if len(objs) == 1:
              return objs[0]
          return ", ".join(objs[:-1]) + " and " + objs[-1]

      # Build phrases using the same phrase_builders but with aggregated objects
      phrases = []
      for (subject, predicate), objects in grouped.items():
          builder = phrase_builders.get(predicate)
          if builder:
              # If the builder expects a single object, we pass the joined string
              phrases.append(builder(subject, join_objects(objects)))
          else:
              # Generic fallback for unhandled predicates
              phrases.append(f"{subject} {predicate} {join_objects(objects)}")

      # Assemble the final single sentence
      if not phrases:
          return ""
